  1→import ThumbUpIcon from '@airlock/material-symbols/svg/outlined/recommend.svg';
  2→import React, { useEffect, useRef } from 'react';
  3→import { Trans, useTranslation } from 'react-i18next';
  4→import { useNavigate } from 'react-router';
  5→
  6→import useTenant from '@airlock-cloud/management-ui/common/use-tenant/useTenant';
  7→import { InfoZone } from '@airlock-cloud/management-ui/components/info-zone';
  8→import { EmbeddedLink } from '@airlock-cloud/management-ui/components/link/Link';
  9→import { Page } from '@airlock-cloud/management-ui/components/page';
 10→import { Text } from '@airlock-cloud/management-ui/components/text';
 11→import { Title } from '@airlock-cloud/management-ui/components/title';
 12→import ConfigurationActionGroup from '@airlock-cloud/management-ui/features/config-wizard/ConfigurationActionGroup';
 13→import OperationActionGroup from '@airlock-cloud/management-ui/features/config-wizard/OperationActionGroup';
 14→import Forbidden from '@airlock-cloud/management-ui/features/errors/Forbidden';
 15→import { useRequiredTenantId } from '@airlock-cloud/management-ui/features/tenants/base/use-tenant-id/useTenantId';
 16→import { PublicPathBuilder } from '@airlock-cloud/management-ui/pages/public.routes';
 17→
 18→function GettingStartedPage() {
 19→	const { t } = useTranslation();
 20→	const tenantId = useRequiredTenantId();
 21→	const { data: tenant } = useTenant(tenantId);
 22→	const navigate = useNavigate();
 23→	const previousTenantId = useRef(tenantId);
 24→	const recommendations = t('pages.configuration.gettingStarted.recommendation.list', {
 25→		returnObjects: true,
 26→		defaultValue: ['Adjust settings below where appropriate', 'Activate and test your tenant'],
 27→	}) as string[];
 28→
 29→	useEffect(() => {
 30→		if (tenantId !== previousTenantId.current && !tenant.isWizardEnabled) {
 31→			navigate(new PublicPathBuilder().appRoutes().configuration().tenants().tenantId(tenantId).build());
 32→		}
 33→		previousTenantId.current = tenantId;
 34→	}, [tenant.isWizardEnabled, tenantId, navigate, previousTenantId]);
 35→
 36→	if (!tenant.isWizardEnabled) {
 37→		return <Forbidden />;
 38→	}
 39→
 40→	return (
 41→		<Page>
 42→			<Page.Head
 43→				title={t('pages.configuration.tenants.tenant.gettingStarted.gettingStartedPage.title', {
 44→					defaultValue: 'Getting started',
 45→				})}
 46→			>
 47→				<Text>
 48→					{t('pages.configuration.tenants.tenant.gettingStarted.gettingStartedPage.description', {
 49→						defaultValue: 'Start and test a configuration within minutes',
 50→					})}
 51→				</Text>
 52→			</Page.Head>
 53→			<Page.Section>
 54→				<InfoZone icon={ThumbUpIcon}>
 55→					<InfoZone.Head>
 56→						{t(
 57→							'pages.configuration.tenants.tenant.gettingStarted.gettingStartedPage.recommendation.title',
 58→							{
 59→								defaultValue: 'Recommended workflow',
 60→							}
 61→						)}
 62→					</InfoZone.Head>
 63→					<InfoZone.Body>
 64→						<ol className="list-inside list-decimal">
 65→							{recommendations.map((recommendation, index) => (
 66→								<li key={index}>{recommendation}</li>
 67→							))}
 68→							<li>
 69→								<Trans
 70→									t={t}
 71→									i18nKey="pages.configuration.tenants.tenant.gettingStarted.gettingStartedPage.recommendation.list.reachOut"
 72→								>
 73→									<EmbeddedLink target="_blank" href="https://jira.airlock.com">
 74→										Reach out to our team
 75→									</EmbeddedLink>{' '}
 76→									for help fine-tuning the configuration
 77→								</Trans>
 78→							</li>
 79→						</ol>
 80→					</InfoZone.Body>
 81→				</InfoZone>
 82→			</Page.Section>
 83→			<Page.Section>
 84→				<Title order={2}>
 85→					{t(
 86→						'pages.configuration.tenants.tenant.gettingStarted.gettingStartedPage.configuration.section.title',
 87→						{ defaultValue: 'Configuration' }
 88→					)}
 89→				</Title>
 90→				<ConfigurationActionGroup />
 91→			</Page.Section>
 92→			<Page.Section>
 93→				<Title order={2}>
 94→					{t('pages.configuration.tenants.tenant.gettingStarted.gettingStartedPage.operation.section.title', {
 95→						defaultValue: 'Operation',
 96→					})}
 97→				</Title>
 98→				<OperationActionGroup />
 99→			</Page.Section>
100→		</Page>
101→	);
102→}
103→
104→export default GettingStartedPage;
105→

 1→import { useTranslation } from 'react-i18next';
 2→
 3→import { saasConfigApi } from '@airlock-cloud/management-ui/api/apis';
 4→import useSetNotification from '@airlock-cloud/management-ui/common/use-set-notification/useSetNotification';
 5→
 6→function useDownloadSaasConfigZip(tenantId: string) {
 7→	const { t } = useTranslation();
 8→	const setNotification = useSetNotification();
 9→
10→	return async () => {
11→		try {
12→			const { blob, filename } = await saasConfigApi.getConfigZip(tenantId);
13→
14→			const url = URL.createObjectURL(blob);
15→
16→			const link = document.createElement('a');
17→			link.href = url;
18→			link.download = filename;
19→			document.body.appendChild(link);
20→			link.click();
21→			document.body.removeChild(link);
22→
23→			URL.revokeObjectURL(url);
24→		} catch {
25→			setNotification({
26→				level: 'error',
27→				message: t('common.serverErrors.unexpected', {
28→					defaultValue: 'An unexpected error occurred. Please try again later or reach out to us.',
29→				}),
30→			});
31→		}
32→	};
33→}
34→
35→export default useDownloadSaasConfigZip;
36→

 1→import { useSuspenseQuery } from '@tanstack/react-query';
 2→
 3→import { saasConfigApi } from '@airlock-cloud/management-ui/api/apis';
 4→
 5→function useSaasConfig(tenantId: string) {
 6→	return useSuspenseQuery({
 7→		queryKey: ['tenants', tenantId, 'saas-config'],
 8→		queryFn: () => saasConfigApi.getSaasConfig(tenantId),
 9→	});
10→}
11→
12→export default useSaasConfig;
